const slugify = (text) => {
	var trMap = {
		'çÇ': 'c',
		'ğĞ': 'g',
		'şŞ': 's',
		'üÜ': 'u',
		'ıİ': 'i',
		'öÖ': 'o',
		'éÉ': 'e'
	};
	for (var key in trMap) {
		text = text.replace(new RegExp('[' + key + ']', 'g'), trMap[key]);
	}
	return text.replace(/[^-a-z0-9\s]+/ig, '') // remove non-alphanumeric chars
		.replace(/\s/gi, "-") // convert spaces to dashes
		.replace(/[-]+/gi, "-") // trim repeated dashes
		.toLowerCase();
}

function fetchVideos(target, fetchedVideos, quality = 640) {
	target.forEach(video => {
		fetch(`https://vimeo.com/api/oembed.json?url=https://vimeo.com/${video}&width=${quality}`)
			.then(res => {
				if (res.ok) {
					return res.json();
				} else {
					return Promise.reject({
						status: res.status,
						statusText: res.statusText
					});
				}
			})
			.then(res => {
				res.slug = slugify(res.title);
				return res
			})
			.then(res => fetchedVideos.push(res))
			.catch(err => console.log('Error, with message:', err.statusText));
	});
}

